import{c as i,Q as l,j as t,m as e}from"./chunks/framework.BPKcPtvA.js";const A=JSON.parse('{"title":"AI资管助手","description":"","frontmatter":{},"headers":[],"relativePath":"using-system/workbench/ai-assistant.md","filePath":"using-system/workbench/ai-assistant.md"}'),r={name:"using-system/workbench/ai-assistant.md"};function o(d,a,h,n,s,u){return l(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="ai资管助手" tabindex="-1">AI资管助手 <a class="header-anchor" href="#ai资管助手" aria-label="Permalink to &quot;AI资管助手&quot;">​</a></h1><p>AI资管助手是系统的智能助理，提供智能化的股权投后管理支持，帮助您高效完成各项投后管理任务。</p><h2 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to &quot;功能介绍&quot;">​</a></h2><h3 id="智能问答" tabindex="-1">智能问答 <a class="header-anchor" href="#智能问答" aria-label="Permalink to &quot;智能问答&quot;">​</a></h3><p>支持自然语言提问，快速获取答案：</p><ul><li>投后管理政策咨询</li><li>企业档案信息查询</li><li>财务数据分析</li><li>风险评估建议</li></ul><h3 id="报告生成" tabindex="-1">报告生成 <a class="header-anchor" href="#报告生成" aria-label="Permalink to &quot;报告生成&quot;">​</a></h3><p>自动生成标准化报告，节省时间成本：</p><ul><li>投后检查报告</li><li>企业评分评级报告</li><li>财务分析报告</li><li>风险评估报告</li></ul><h3 id="数据分析" tabindex="-1">数据分析 <a class="header-anchor" href="#数据分析" aria-label="Permalink to &quot;数据分析&quot;">​</a></h3><p>提供数据分析和趋势预测：</p><ul><li>财务数据趋势分析</li><li>行业对标分析</li><li>投资回报分析</li><li>风险预警分析</li></ul><h3 id="ai模板辅助" tabindex="-1">AI模板辅助 <a class="header-anchor" href="#ai模板辅助" aria-label="Permalink to &quot;AI模板辅助&quot;">​</a></h3><p>AI智能辅助任务模板管理，提升工作效率：</p><h4 id="ai智能推荐模板" tabindex="-1">AI智能推荐模板 <a class="header-anchor" href="#ai智能推荐模板" aria-label="Permalink to &quot;AI智能推荐模板&quot;">​</a></h4><p>根据任务类型、企业特征、历史数据，AI自动推荐最合适的模板：</p><ul><li>分析任务类型和目标</li><li>识别企业行业、规模、发展阶段</li><li>参考历史任务执行情况</li><li>匹配集团最新政策和标准</li><li>提供匹配度评分和推荐理由</li></ul><p><strong>使用方式</strong>：</p><ol><li>在任务创建页面，点击「AI推荐模板」</li><li>输入任务描述，例如：&quot;对XX科技进行季度综合评分&quot;</li><li>AI分析后推荐3-5个候选模板</li><li>查看推荐理由和匹配度评分</li><li>选择最合适的模板应用</li></ol><h4 id="ai自动生成模板" tabindex="-1">AI自动生成模板 <a class="header-anchor" href="#ai自动生成模板" aria-label="Permalink to &quot;AI自动生成模板&quot;">​</a></h4><p>基于自然语言描述，AI快速生成符合规范的任务模板：</p><p><strong>自然语言生成示例</strong>：</p><ul><li><p><strong>输入</strong>：&quot;为制造业企业创建年度综合评分模板，重点关注财务指标和经营能力&quot;</p></li><li><p><strong>AI生成</strong>：自动创建包含财务指标（营收增长率、净利润率等）和经营能力（市场份额、客户满意度等）维度的评分模板</p></li><li><p><strong>输入</strong>：&quot;创建符合集团2024年统计口径的季度财报模板&quot;</p></li><li><p><strong>AI生成</strong>：自动匹配最新统计口径，生成资产负债表、利润表、现金流量表模板</p></li></ul><p><strong>历史任务学习</strong>： AI学习历史优秀任务，自动生成优化模板：</p><ul><li>分析历史任务执行效果</li><li>识别最佳实践和常见问题</li><li>生成改进后的模板版本</li></ul><h4 id="ai智能填充" tabindex="-1">AI智能填充 <a class="header-anchor" href="#ai智能填充" aria-label="Permalink to &quot;AI智能填充&quot;">​</a></h4><p>AI自动填充企业信息和关键数据：</p><p><strong>自动填充企业信息</strong>：</p><ul><li>企业名称、企业代码</li><li>所属行业、企业规模</li><li>投资时间、投资金额</li><li>历史评分评级结果</li></ul><p><strong>自动填充评估参数</strong>：</p><ul><li>评估周期：根据任务类型自动计算</li><li>统计口径：自动匹配最新版本</li><li>评分标准：根据企业类型调整</li><li>截止时间：根据工作日历智能推荐</li></ul><p><strong>自动填充参考数据</strong>：</p><ul><li>历史财务数据</li><li>行业平均水平</li><li>同类企业对比数据</li><li>风险等级参考</li></ul><h4 id="ai模板优化" tabindex="-1">AI模板优化 <a class="header-anchor" href="#ai模板优化" aria-label="Permalink to &quot;AI模板优化&quot;">​</a></h4><p>AI分析历史任务执行情况，提供模板优化建议：</p><p><strong>执行效果分析</strong>：</p><ul><li>任务完成率</li><li>数据质量评分</li><li>用户反馈汇总</li><li>问题识别和改进建议</li></ul><p><strong>智能优化建议</strong>：</p><ul><li>调整评分维度和权重</li><li>优化数据采集字段</li><li>改进流程和步骤</li><li>增加质量控制点</li></ul><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><h3 id="智能问答使用" tabindex="-1">智能问答使用 <a class="header-anchor" href="#智能问答使用" aria-label="Permalink to &quot;智能问答使用&quot;">​</a></h3><ol><li>在资管工作台中找到AI助手入口</li><li>输入您的问题或需求</li><li>系统自动生成回答或建议</li></ol><h3 id="报告生成使用" tabindex="-1">报告生成使用 <a class="header-anchor" href="#报告生成使用" aria-label="Permalink to &quot;报告生成使用&quot;">​</a></h3><ol><li>选择报告类型</li><li>输入关键参数</li><li>AI自动生成报告初稿</li><li>人工审核和调整</li></ol><h3 id="ai模板辅助使用" tabindex="-1">AI模板辅助使用 <a class="header-anchor" href="#ai模板辅助使用" aria-label="Permalink to &quot;AI模板辅助使用&quot;">​</a></h3><ol><li>在任务创建页面，点击「AI推荐模板」或「AI生成模板」</li><li>输入任务描述或需求</li><li>AI推荐或生成模板</li><li>AI自动填充关键数据</li><li>确认后创建任务</li></ol><h2 id="ai模板变量" tabindex="-1">AI模板变量 <a class="header-anchor" href="#ai模板变量" aria-label="Permalink to &quot;AI模板变量&quot;">​</a></h2><p>支持在模板中使用AI动态变量，创建任务时AI自动填充：</p><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>AI填充示例</th></tr></thead><tbody><tr><td><code>{企业名称}</code></td><td>关联投资企业名称</td><td>XX科技有限公司</td></tr><tr><td><code>{企业代码}</code></td><td>企业在集团的统一编码</td><td>ENT-2024-001</td></tr><tr><td><code>{企业类型}</code></td><td>AI识别的企业类型</td><td>科技型企业</td></tr><tr><td><code>{所属行业}</code></td><td>企业所属行业</td><td>信息技术</td></tr><tr><td><code>{评估周期}</code></td><td>当前评估周期</td><td>2024年Q1</td></tr><tr><td><code>{统计口径}</code></td><td>AI匹配的最新统计口径版本</td><td>V2024.03</td></tr><tr><td><code>{报告截止日}</code></td><td>AI计算的报告提交截止日期</td><td>2024-03-31</td></tr><tr><td><code>{历史评分}</code></td><td>企业历史评分评级结果</td><td>AA级，综合评分85分</td></tr><tr><td><code>{行业平均}</code></td><td>行业平均水平数据</td><td>行业平均营收增长率15%</td></tr><tr><td><code>{风险等级}</code></td><td>AI评估的企业风险等级</td><td>中风险</td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="ai推荐使用建议" tabindex="-1">AI推荐使用建议 <a class="header-anchor" href="#ai推荐使用建议" aria-label="Permalink to &quot;AI推荐使用建议&quot;">​</a></h3><ul><li>优先使用AI推荐的模板，匹配度更高</li><li>仔细阅读AI的推荐理由，了解推荐依据</li><li>如AI推荐不合适，可手动选择其他模板</li><li>及时反馈AI推荐效果，帮助AI持续优化</li></ul><h3 id="ai生成质量保证" tabindex="-1">AI生成质量保证 <a class="header-anchor" href="#ai生成质量保证" aria-label="Permalink to &quot;AI生成质量保证&quot;">​</a></h3><ul><li>AI生成后务必人工审核</li><li>确认模板内容符合集团规范</li><li>根据实际情况调整模板内容</li><li>重要任务建议使用标准模板</li></ul><h3 id="数据准确性" tabindex="-1">数据准确性 <a class="header-anchor" href="#数据准确性" aria-label="Permalink to &quot;数据准确性&quot;">​</a></h3><ul><li>AI填充的数据需核对准确性</li><li>关键数据建议人工确认</li><li>发现数据错误及时反馈</li><li>定期更新企业基础信息</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-ai推荐的模板一定是最合适的吗" tabindex="-1">Q：AI推荐的模板一定是最合适的吗？ <a class="header-anchor" href="#q-ai推荐的模板一定是最合适的吗" aria-label="Permalink to &quot;Q：AI推荐的模板一定是最合适的吗？&quot;">​</a></h3><p>A：AI推荐基于多维度分析，匹配度较高，但仍需人工确认。建议查看AI的推荐理由，结合实际情况选择最合适的模板。</p><h3 id="q-ai生成的模板可以使用吗" tabindex="-1">Q：AI生成的模板可以使用吗？ <a class="header-anchor" href="#q-ai生成的模板可以使用吗" aria-label="Permalink to &quot;Q：AI生成的模板可以使用吗？&quot;">​</a></h3><p>A：AI生成的模板可以参考使用，但务必人工审核确认。重要任务建议使用经过验证的标准模板。</p><h3 id="q-如何让ai推荐更准确" tabindex="-1">Q：如何让AI推荐更准确？ <a class="header-anchor" href="#q-如何让ai推荐更准确" aria-label="Permalink to &quot;Q：如何让AI推荐更准确？&quot;">​</a></h3><p>A：提供详细的任务描述，包括任务目标、企业特征、时间要求等信息，AI分析越充分，推荐越准确。</p><h3 id="q-ai会学习我的使用习惯吗" tabindex="-1">Q：AI会学习我的使用习惯吗？ <a class="header-anchor" href="#q-ai会学习我的使用习惯吗" aria-label="Permalink to &quot;Q：AI会学习我的使用习惯吗？&quot;">​</a></h3><p>A：是的，AI会学习您的历史任务和模板使用习惯，随着使用次数增加，推荐会越来越精准。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="/using-system/workbench/standard-report.html">标准函件报告</a></li><li><a href="/using-system/workbench/custom-report.html">自定义报告</a></li><li><a href="/using-system/task-management/templates.html">引入模板</a></li></ul>',67)])])}const I=i(r,[["render",o]]);export{A as __pageData,I as default};
